                    out.append(s[i])
                else:
                    out.append(s[j])
                    j -= 1
                i += 1

        # If rev is True at the end, we've taken from the right in the loop,
        # so we just need to append remaining non-'i' characters from the right.
        if rev:
            while j >= i:
                if s[j] != 'i':
